    "quelle": {"autor": "Johann Jacob Bodmer", "werk": "Sammlung von Minnesingern aus dem schwäbischen Zeitpuncte", "jahr": "1758", "fundstelleUrl": "https://www.e-rara.ch/zut/content/pageview/258009"},
