    "quelle": {"autor": "Ernst Ludwig Rochholz", "werk": "Schweizersagen aus dem Aargau, Erster Band, Abschnitt Erdgeister", "jahr": "1856", "fundstelleUrl": "https://archive.org/details/schweizersagena00rochgoog"},
